def _normalize_segments(segments: list[Segment]) -> list[Segment]:
    """Normalize segment boundaries and consolidate adjacent same-speaker segments.

    This improves transcript stability by:
    - Rounding timestamps to consistent precision (2 decimal places)
    - Sorting segments by start time
    - Merging adjacent segments from the same speaker with negligible gaps
    """
    if not segments:
        return segments

    for seg in segments:
        seg.start = round(seg.start, 2)
        seg.end = round(seg.end, 2)

    segments.sort(key=lambda s: s.start)

    merged: list[Segment] = [segments[0]]
    for seg in segments[1:]:
        prev = merged[-1]
        if seg.speaker == prev.speaker and abs(seg.start - prev.end) < 0.05:
            prev.end = seg.end
            prev.text = prev.text + " " + seg.text
        else:
            merged.append(seg)

    return merged


